   393→  const handlePmDragStart = (pmId: string, sourceDate: string) => {
   394→    // Find PM in tactical data
   395→    const pm = tacticalData?.pmBlocks.find(p => p.pmId === pmId);
   396→    if (!pm) return;
   397→
   398→    // Store drag info
   399→    draggingPmRef.current = {
   400→      pmId,
   401→      pmCode: pm.pmCode,
   402→      trainId: pm.trainId,
   403→      trainNumber: pm.trainNumber,
   404→      sourceDate,
   405→      constraintStart: pm.constraintStart,
   406→      constraintEnd: pm.constraintEnd,
   407→      isLocked: pm.isLocked,
   408→    };
   409→
   410→    // Initialize drag state in PM slice
   411→    pmActions.startDrag({ pmId, sourceDate });
   412→
   413→    // Set initial validation (quick check)
   414→    const quickResult = quickValidatePmMove({
   415→      pmId,
   416→      currentDate: sourceDate,
   417→      targetDate: sourceDate,
   418→      trainId: pm.trainId,
   419→      constraintStart: pm.constraintStart,
   420→      constraintEnd: pm.constraintEnd,
   421→      isLocked: pm.isLocked,
   422→    });
   423→    dragValidationRef.current = quickResult;
   424→    pmActions.setDragValidation({
   425→      isValid: quickResult.isValid,
   426→      message: quickResult.message,
   427→      violations: quickResult.violations,
   428→    });
   429→  };
   430→
   431→  const handlePmDragMove = (pmId: string, targetDate: string) => {
   432→    const dragInfo = draggingPmRef.current;
   433→    if (!dragInfo || dragInfo.pmId !== pmId) return;
   434→
   435→    // Update target date in PM slice
   436→    pmActions.updateDragTarget(targetDate);
   437→
   438→    // Quick client-side validation
   439→    const quickResult = quickValidatePmMove({
   440→      pmId,
   441→      currentDate: dragInfo.sourceDate,
   442→      targetDate,
   443→      trainId: dragInfo.trainId,
   444→      constraintStart: dragInfo.constraintStart,
   445→      constraintEnd: dragInfo.constraintEnd,
   446→      isLocked: dragInfo.isLocked,
   447→    });
   448→    dragValidationRef.current = quickResult;
   449→    pmActions.setDragValidation({
   450→      isValid: quickResult.isValid,
   451→      message: quickResult.message,
   452→      violations: quickResult.violations,
   453→    });
   454→
   455→    // If quick validation passes, trigger debounced API validation
   456→    if (quickResult.isValid && targetDate !== dragInfo.sourceDate) {
   457→      debouncedValidationRef.current.validate({
   458→        pmId,
   459→        currentDate: dragInfo.sourceDate,
   460→        targetDate,
   461→        trainId: dragInfo.trainId,
   462→      });
   463→    }
   464→  };
   465→
   466→  const handlePmDragEnd = async (pmId: string, targetDate: string) => {
   467→    const dragInfo = draggingPmRef.current;
   468→    if (!dragInfo || dragInfo.pmId !== pmId) {
   469→      // Clear drag state
   470→      pmActions.cancelDrag();
   471→      draggingPmRef.current = null;
   472→      return;
   473→    }
   474→
   475→    // Cancel pending validation
   476→    debouncedValidationRef.current.cancel();
   477→
   478→    // If no change, just cancel
   479→    if (targetDate === dragInfo.sourceDate) {
   480→      pmActions.cancelDrag();
   481→      draggingPmRef.current = null;
   482→      return;
   483→    }
   484→
   485→    // Final quick validation
   486→    const finalValidation = quickValidatePmMove({
   487→      pmId,
   488→      currentDate: dragInfo.sourceDate,
   489→      targetDate,
   490→      trainId: dragInfo.trainId,
   491→      constraintStart: dragInfo.constraintStart,
   492→      constraintEnd: dragInfo.constraintEnd,
   493→      isLocked: dragInfo.isLocked,
   494→    });
   495→
   496→    // If invalid, snap back and show toast
   497→    if (!finalValidation.isValid) {
   498→      pmActions.cancelDrag();
   499→      draggingPmRef.current = null;
   500→      void showToast({
   501→        intent: Intent.DANGER,
   502→        icon: 'error',
   503→        message: finalValidation.message || 'Cannot reschedule: constraint violation',
   504→        timeout: 5000,
   505→      });
   506→      return;
   507→    }
   508→
   509→    // Open confirmation dialog
   510→    dragConfirmRef.current = {
   511→      isOpen: true,
   512→      pmId,
   513→      pmCode: dragInfo.pmCode,
   514→      trainNumber: dragInfo.trainNumber,
   515→      sourceDate: dragInfo.sourceDate,
   516→      targetDate,
   517→      impact: null,
   518→      isLoadingImpact: true,
   519→    };
   520→    // Force re-render by ending drag with commit=false (optimistic update)
   521→    pmActions.endDrag(false);
   522→
   523→    // Load impact assessment
   524→    try {
   525→      const impact = await getPmMoveImpact({
   526→        pmId,
   527→        currentDate: dragInfo.sourceDate,
   528→        targetDate,
   529→        trainId: dragInfo.trainId,
   530→      });
   531→      dragConfirmRef.current = {
   532→        ...dragConfirmRef.current,
   533→        impact,
   534→        isLoadingImpact: false,
   535→      };
   536→    } catch {
   537→      dragConfirmRef.current = {
   538→        ...dragConfirmRef.current,
   539→        isLoadingImpact: false,
   540→      };
   541→    }
   542→
   543→    // Keep draggingPmRef for the confirmation dialog
   544→  };
   545→
   546→  const handleDragConfirm = async () => {
   547→    const confirmState = dragConfirmRef.current;
   548→    const dragInfo = draggingPmRef.current;
   549→
   550→    if (!confirmState.pmId || !dragInfo) {
   551→      handleDragCancel();
   552→      return;
   553→    }
   554→
   555→    try {
   556→      // Commit the move to API
   557→      await commitPmMove({
   558→        pmId: confirmState.pmId,
   559→        currentDate: confirmState.sourceDate,
   560→        targetDate: confirmState.targetDate,
   561→        trainId: dragInfo.trainId,
   562→        reason: 'Manual reschedule via canvas drag-and-drop',
   563→      });
   564→
   565→      // Confirm move in PM slice (updates local state)
   566→      pmActions.confirmMove(confirmState.pmId);
   567→
   568→      // Show success toast
   569→      void showToast({
   570→        intent: Intent.SUCCESS,
   571→        icon: 'tick',
   572→        message: `${confirmState.pmCode} rescheduled to ${confirmState.targetDate}`,
   573→        timeout: 3000,
   574→      });
   575→
   576→      // Reload tactical data to reflect changes
   577→      handleLoadTacticalData();
   578→    } catch (error) {
   579→      // Reject move (revert to original date)
   580→      pmActions.rejectMove(confirmState.pmId);
   581→
   582→      // Show error toast
   583→      void showToast({
   584→        intent: Intent.DANGER,
   585→        icon: 'error',
   586→        message: error instanceof Error ? error.message : 'Failed to reschedule PM',
   587→        timeout: 5000,
   588→      });
   589→    } finally {
   590→      // Close dialog and clear state
   591→      dragConfirmRef.current = initialDragConfirmState;
   592→      draggingPmRef.current = null;
   593→    }
   594→  };
